import{_ as t,c as o,o as r,a3 as s}from"./chunks/framework.DpzXWsSh.js";const P=JSON.parse('{"title":"前端工程化 -- 上线部署","description":"","frontmatter":{"title":"前端工程化 -- 上线部署","date":"2024-9-14","categories":["工程化"]},"headers":[],"relativePath":"blogs/engineering/20240917.md","filePath":"blogs/engineering/20240917.md"}'),n={name:"blogs/engineering/20240917.md"},l=s('<h2 id="基本概念" tabindex="-1">基本概念 <a class="header-anchor" href="#基本概念" aria-label="Permalink to &quot;基本概念&quot;">​</a></h2><h3 id="域名" tabindex="-1">域名 <a class="header-anchor" href="#域名" aria-label="Permalink to &quot;域名&quot;">​</a></h3><p>域名俗称网址，是由一串用点分隔的名字组成，用于标识互联网上的计算机。</p><p>原本用于标识互联网上计算机使用的是 IP 地址，但是由于 IP 地址不便于记忆，所以人们便设计出来比较容易记忆的域名，然后通过 <strong>DNS</strong> 将<strong>域名</strong>和 <strong>IP 地址</strong>关联，这样人们便可以通过记忆域名直接访问到对应的计算机。</p><h3 id="dns-服务器" tabindex="-1">DNS 服务器 <a class="header-anchor" href="#dns-服务器" aria-label="Permalink to &quot;DNS 服务器&quot;">​</a></h3><p>DNS (Domain Name System)，可以理解为互联网上的一项服务，他可以将域名转换成其对应的 IP 地址。</p><p>可以将其理解为字典，字典中存储的就是域名和 IP 地址一一对应的键值对。</p><h3 id="服务器" tabindex="-1">服务器 <a class="header-anchor" href="#服务器" aria-label="Permalink to &quot;服务器&quot;">​</a></h3><p>服务器其实就是一台计算机，但是这台计算机并和我们自己的的 PC 不一样，不是日常使用的，而是提供某项互联网服务的。</p><p>比如 web 服务器，能为我们提供网页服务，email 服务器，能为我们提供电子邮件服务，FTP 服务器能为我们提供文件存储服务等等。</p><p>为计算机安装不同的服务应用程序，即可提供相应的服务。</p><p>常见的web 服务应用程序： Apache、Nginx、IIS、Node.js</p><h3 id="本地-hosts-文件" tabindex="-1">本地 hosts 文件 <a class="header-anchor" href="#本地-hosts-文件" aria-label="Permalink to &quot;本地 hosts 文件&quot;">​</a></h3><p>当你的计算机尝试解析一个域名时，它<strong>首先会检查 hosts 文件中是否存在相应的映射</strong>。如果找到了匹配的 IP 地址，那么它就会直接使用这个 IP 地址；如果没有找到，才会继续通过 DNS 服务器进行解析。</p><ul><li><code>windows: c:\\windows\\system32\\drivers\\etc\\hosts</code></li><li><code>mac: /etc/hosts</code></li></ul><h2 id="网站请求流程-简化版" tabindex="-1">网站请求流程（简化版） <a class="header-anchor" href="#网站请求流程-简化版" aria-label="Permalink to &quot;网站请求流程（简化版）&quot;">​</a></h2><h3 id="静态页面" tabindex="-1">静态页面 <a class="header-anchor" href="#静态页面" aria-label="Permalink to &quot;静态页面&quot;">​</a></h3><p><strong>过程：</strong></p><ol><li><strong>用户请求</strong>：用户在浏览器中输入一个URL或点击一个链接，浏览器向服务器发送一个HTTP请求。</li><li><strong>服务器响应</strong>：服务器接收到请求后，查找对应的HTML、CSS、JavaScript文件，并将这些文件作为响应返回给浏览器。</li><li><strong>浏览器渲染</strong>：浏览器接收到响应后，解析HTML文件，并根据HTML文件中的链接加载CSS和JavaScript文件。然后，浏览器根据这些文件渲染页面。</li></ol><p><strong>重点：</strong></p><ul><li><strong>无数据通信</strong>：静态页面不涉及与服务器的任何数据通信，所有内容都是预先写好的。</li><li><strong>快速加载</strong>：由于没有数据请求，静态页面加载速度较快。</li><li><strong>适合简单内容</strong>：适合展示静态内容，如公司简介、产品介绍等。</li></ul><h3 id="动态页面" tabindex="-1">动态页面 <a class="header-anchor" href="#动态页面" aria-label="Permalink to &quot;动态页面&quot;">​</a></h3><p><strong>过程：</strong></p><ol><li><strong>用户请求</strong>：用户在浏览器中输入一个URL或点击一个链接，浏览器向服务器发送一个HTTP请求。</li><li><strong>服务器响应</strong>：服务器接收到请求后，可能会与数据库或其他服务进行交互，获取动态数据。</li><li><strong>生成页面</strong>：服务器根据获取的数据动态生成HTML页面。</li><li><strong>响应返回</strong>：服务器将生成的HTML页面作为响应返回给浏览器。</li><li><strong>浏览器渲染</strong>：浏览器接收到响应后，解析HTML页面并渲染。</li></ol><p><strong>重点：</strong></p><ul><li><strong>数据通信</strong>：动态页面涉及与服务器的多次数据通信，通常包括数据库查询、API调用等。</li><li><strong>内容动态生成</strong>：页面内容是根据服务器端的数据动态生成的。</li><li><strong>适合复杂应用</strong>：适合需要频繁更新内容的应用，如社交网络、电子商务等。</li></ul><h3 id="前后端分离的页面" tabindex="-1">前后端分离的页面 <a class="header-anchor" href="#前后端分离的页面" aria-label="Permalink to &quot;前后端分离的页面&quot;">​</a></h3><p><strong>过程：</strong></p><ol><li><strong>静态页面请求：</strong></li></ol><ul><li><strong>用户请求</strong>：用户在浏览器中输入一个URL或点击一个链接，浏览器向服务器发送一个HTTP请求。</li><li><strong>服务器响应</strong>：服务器返回一个静态的HTML页面，通常只包含基本的HTML结构和一些JavaScript代码。</li><li><strong>浏览器渲染</strong>：浏览器接收到响应后，解析HTML页面并渲染。</li></ul><ol start="2"><li><strong>Ajax数据请求：</strong></li></ol><ul><li><strong>JavaScript发起请求</strong>：浏览器中的JavaScript代码（通常是使用Ajax或Fetch API）向服务器发送一个数据请求。</li><li><strong>服务器处理</strong>：服务器接收到请求后，处理请求并返回JSON格式的数据。</li><li><strong>数据渲染</strong>：浏览器接收到数据后，使用JavaScript动态地将数据渲染到页面上。</li></ul><p><strong>重点：</strong></p><ul><li><strong>前后端职责分离</strong>：前端负责页面渲染和用户交互，后端负责数据处理和业务逻辑。</li><li><strong>灵活性高</strong>：前端可以独立开发和部署，后端也可以独立开发和部署，两者通过API进行通信。</li><li><strong>适合复杂应用</strong>：适合需要高度交互性和复杂用户界面的应用，如单页应用（SPA）。</li></ul><h3 id="前后端不分离的页面" tabindex="-1">前后端不分离的页面 <a class="header-anchor" href="#前后端不分离的页面" aria-label="Permalink to &quot;前后端不分离的页面&quot;">​</a></h3><p><strong>过程：</strong></p><ol><li><strong>用户请求</strong>：用户在浏览器中输入一个URL或点击一个链接，浏览器向服务器发送一个HTTP请求。</li><li><strong>服务器处理</strong>：服务器接收到请求后，与数据库或其他服务进行交互，获取数据。</li><li><strong>生成页面</strong>：服务器根据获取的数据动态生成完整的HTML页面。</li><li><strong>响应返回</strong>：服务器将生成的HTML页面作为响应返回给浏览器。</li><li><strong>浏览器渲染</strong>：浏览器接收到响应后，解析HTML页面并渲染。</li></ol><p><strong>重点：</strong></p><ul><li><strong>一次请求完成</strong>：整个页面的生成和渲染都在服务器端完成，浏览器只需要接收并显示最终的HTML页面。</li><li><strong>适合简单应用</strong>：适合不需要频繁更新内容的简单应用，如企业官网、博客等。</li><li><strong>SEO友好</strong>：由于页面内容在服务器端生成，搜索引擎可以更好地抓取和索引页面内容。</li></ul>',39),a=[l];function i(e,g,h,c,d,p){return r(),o("div",null,a)}const T=t(n,[["render",i]]);export{P as __pageData,T as default};
